class Solution:
    def largestSubmatrix(self, matrix):
        m = len(matrix)
        n = len(matrix[0])
        prefix = [[0] * n for _ in range(m + 1)]
        for i in range(m):
            for j in range(n):
                prefix[i + 1][j] = prefix[i][j] + matrix[i][j]
        best = 0
        for top in range(m):
            for bottom in range(top, m):
                height = bottom - top + 1
                width = 0
                for j in range(n):
                    col_ones = prefix[bottom + 1][j] - prefix[top][j]
                    if col_ones == height:
                        width += 1
                area = width * height
                if area > best:
                    best = area
        return best

