class Solution:
    def largestSubmatrix(self, matrix):
        m = len(matrix)
        n = len(matrix[0])
        heights = [[0] * n for _ in range(m)]
        for j in range(n):
            for i in range(m):
                if matrix[i][j] == 1:
                    heights[i][j] = (heights[i - 1][j] + 1) if i > 0 else 1
                else:
                    heights[i][j] = 0
        best = 0
        for i in range(m):
            row = sorted(heights[i], reverse=True)
            for k in range(n):
                area = row[k] * (k + 1)
                if area > best:
                    best = area
        return best

