var largestSubmatrix = function(matrix) {
    const m = matrix.length;
    const n = matrix[0].length;
    const heights = Array.from({ length: m }, () => new Array(n).fill(0));
    for (let j = 0; j < n; j++) {
        for (let i = 0; i < m; i++) {
            if (matrix[i][j] === 1) {
                heights[i][j] = i > 0 ? heights[i - 1][j] + 1 : 1;
            } else {
                heights[i][j] = 0;
            }
        }
    }
    let best = 0;
    for (let i = 0; i < m; i++) {
        const row = heights[i].slice().sort((a, b) => b - a);
        for (let k = 0; k < n; k++) {
            const area = row[k] * (k + 1);
            if (area > best) best = area;
        }
    }
    return best;
};
